import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,o as s,r as c,s as l,t as u}from"./chunks/javap.CpTN0-Ru.js";const d=JSON.parse(`{"title":"VS Code 提示和技巧","description":"有用的提示和技巧让你的工作更轻松。","frontmatter":{"title":"VS Code 提示和技巧","description":"有用的提示和技巧让你的工作更轻松。","authors":["dicedpixels"],"prev":{"text":"在 VS Code 中生成源代码","link":"./generating-sources"},"next":false,"files":[]},"headers":[],"relativePath":"zh_cn/develop/getting-started/vscode/tips-and-tricks.md","filePath":"translated/zh_cn/develop/getting-started/vscode/tips-and-tricks.md","lastUpdated":1771681070000}`);var f={name:`zh_cn/develop/getting-started/vscode/tips-and-tricks.md`};function p(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">VS Code 提示和技巧 <a class="header-anchor" href="#h1" aria-label="Permalink to “VS Code 提示和技巧”">​</a></h1><p>学习如何翻阅生成的源代码非常重要，这样你才能调试并理解 Minecraft 的内部工作原理。 这里我们概述了一些常见的 IDE 用法。</p><h2 id="searching-for-a-minecraft-class" tabindex="-1">搜索 Minecraft 类 <a class="header-anchor" href="#searching-for-a-minecraft-class" aria-label="Permalink to “搜索 Minecraft 类”">​</a></h2><p>生成源代码后，你就应该可以搜索或查看 Minecraft 类。</p><h3 id="viewing-class-definitions" tabindex="-1">查看类定义 <a class="header-anchor" href="#viewing-class-definitions" aria-label="Permalink to “查看类定义”">​</a></h3><p><strong>快速打开</strong>（<kbd>Ctrl</kbd>+<kbd>P</kbd>）：输入<code>#</code> 后跟类名（例如 <code>#Identifier</code>）。</p><p><img src="/assets/develop/getting-started/vscode/quick-open.png" alt="快速打开" loading="lazy"></p><p><strong>转到定义</strong>（<kbd>F12</kbd>）：从源代码中，通过按 <kbd>Ctrl</kbd> + 单击其名称，或右键单击它并选择“转到定义”导航到类定义。</p><p><img src="/assets/develop/getting-started/vscode/go-to-definition.png" alt="转到定义" loading="lazy"></p><h3 id="finding-references" tabindex="-1">查找引用 <a class="header-anchor" href="#finding-references" aria-label="Permalink to “查找引用”">​</a></h3><p>你可以通过右键单击类名并单击<strong>查找所有引用</strong>来查找类的所有使用情况。</p><p><img src="/assets/develop/getting-started/vscode/find-all-references.png" alt="查找所有引用" loading="lazy"></p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>如果上述函数无法按预期工作，很可能是源文件没有正确附加。 这通常可以通过清理工作区缓存来修复。</p><ul><li>单击状态栏中的<strong>显示 Java 状态菜单</strong>按钮。</li></ul><p><img src="/assets/develop/getting-started/vscode/java-ready.png" alt="显示 Java 状态" loading="lazy"></p><ul><li>在刚刚打开的菜单中，点击**清除工作区缓存...**并确认操作。</li></ul><p><img src="/assets/develop/getting-started/vscode/clear-workspace.png" alt="清理工作区" loading="lazy"></p><ul><li>关闭并重新打开项目。</li></ul></div><h2 id="viewing-bytecode" tabindex="-1">查看字节码 <a class="header-anchor" href="#viewing-bytecode" aria-label="Permalink to “查看字节码”">​</a></h2><p>在编写 mixins 时，查看字节码是必要的。 然而，Visual Studio Code 缺乏对字节码查看的原生支持，而添加此功能的几个扩展可能无法正常工作。</p><p>在这种情况下，你可以使用 Java 的内置 <code>javap</code> 来查看字节码。</p><ul><li><p><strong>定位 Minecraft JAR 的路径：</strong></p><p>打开资源管理器视图，展开 <strong>Java Projects</strong> 部分。 展开项目树中的 <strong>Reference Libraries</strong> 节点，并找到名称中包含 <code>minecraft-</code> 的 JAR 文件。 右键单击该 JAR 文件并复制完整路径。</p><p>它可能看起来像这样：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span></span></code></pre></div></li></ul><p><img src="/assets/develop/getting-started/vscode/copy-path.png" alt="复制路径" loading="lazy"></p><ul><li><p><strong>运行 <code>javap</code>：</strong></p><p>然后，你可以通过将上述路径作为 <code>cp</code>（类路径）并提供完全限定的类名作为最后一个参数来运行 <code>javap</code> 。</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">javap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -private</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.minecraft.util.Identifier</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这将打印字节码到你的终端输出。</p></li></ul><p><img src="/assets/develop/getting-started/vscode/javap.png" alt="javap" loading="lazy"></p>`,20)]])}var m=r(f,[[`render`,p]]);export{d as __pageData,m as default};